// SPDX-License-Identifier: ISC
//! Replay of frozen OnGetInitState vectors generated by an in-package
//! dump that built real regnet chains from dcrd's own fullblocktests
//! generator (one past the stake validation height, one below it)
//! with an empty mempool and drove dcrd's real OnGetInitState over a
//! live piped serverPeer at release-v2.1.5.  Each row freezes the
//! requested types, the SortParentsByVotes/vote/tspend seam outputs,
//! and the pushed MsgInitState.  The empty mempool leaves the seams
//! empty, so the dump pins the once-sent flag, the below-stake
//! blank gate, and the past-stake empty push; the rich assembly (the
//! block cap, the vote extension, the clear-when-only-votes rule, and
//! the wire limits) is pinned directly with crafted facts, since it
//! requires a voting mempool the dump cannot cheaply seed.

// Index arithmetic over pinned vector rows.
#![allow(clippy::arithmetic_side_effects)]

use dcroxide_chainhash::Hash;
use dcroxide_node::server::{
    InitStateWants, MAX_IS_BLOCKS_AT_HEAD, MAX_IS_TSPENDS_AT_HEAD, MAX_IS_VOTES_AT_HEAD,
    OnGetInitStateOutcome, on_get_init_state,
};

const VECTORS: &str = include_str!("data/srvinitstate_vectors.txt");

fn h(b: u8) -> Hash {
    let mut x = [0u8; 32];
    x[0] = b;
    Hash(x)
}

fn parse_hash(s: &str) -> Hash {
    let bytes: Vec<u8> = (0..s.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&s[i..i + 2], 16).unwrap())
        .collect();
    let mut x = [0u8; 32];
    for (i, b) in bytes.iter().rev().enumerate() {
        x[i] = *b;
    }
    Hash(x)
}

fn parse_hashes(s: &str) -> Vec<Hash> {
    if s.is_empty() {
        return Vec::new();
    }
    s.split(',').map(parse_hash).collect()
}

#[test]
fn init_state_matches_dcrd() {
    for line in VECTORS.lines() {
        // is|name|initSent|bestHeight|svh|wantB|wantV|wantT|eligible|pushed|blocks|votes|tspends
        let f: Vec<&str> = line.split('|').collect();
        assert_eq!(f[0], "is");
        let name = f[1];
        let init_sent: bool = f[2].parse().unwrap();
        let best_height: i64 = f[3].parse().unwrap();
        let svh: i64 = f[4].parse().unwrap();
        let wants = InitStateWants {
            blocks: f[5].parse().unwrap(),
            votes: f[6].parse().unwrap(),
            tspends: f[7].parse().unwrap(),
        };
        let eligible = parse_hashes(f[8]);
        let pushed: bool = f[9].parse().unwrap();
        let pushed_blocks = parse_hashes(f[10]);
        let pushed_votes = parse_hashes(f[11]);
        let pushed_tspends = parse_hashes(f[12]);

        // The empty mempool means no votes or treasury spends.
        let out = on_get_init_state(
            init_sent,
            best_height,
            svh,
            wants,
            &eligible,
            |_| Vec::new(),
            &[],
        );

        match out {
            OnGetInitStateOutcome::Ban(_) | OnGetInitStateOutcome::BuildError => {
                assert!(!pushed, "row {name}: expected no push");
            }
            OnGetInitStateOutcome::Blank => {
                assert!(pushed, "row {name}: expected push");
                assert!(
                    pushed_blocks.is_empty()
                        && pushed_votes.is_empty()
                        && pushed_tspends.is_empty()
                );
            }
            OnGetInitStateOutcome::Filled {
                block_hashes,
                vote_hashes,
                tspend_hashes,
            } => {
                assert!(pushed, "row {name}: expected push");
                assert_eq!(block_hashes, pushed_blocks, "row {name} blocks");
                assert_eq!(vote_hashes, pushed_votes, "row {name} votes");
                assert_eq!(tspend_hashes, pushed_tspends, "row {name} tspends");
            }
        }
    }
}

/// The block cap, vote extension, clear-when-only-votes rule, and wire
/// limits — the assembly the empty-mempool dump cannot exercise.
#[test]
fn init_state_assembly() {
    let svh = 144;
    let past = svh; // past the stake validation height
    let both = InitStateWants {
        blocks: true,
        votes: true,
        tspends: true,
    };

    // A repeated request bans regardless of everything else (dcrd
    // 2.2; older versions ignored it).
    assert_eq!(
        on_get_init_state(true, past, svh, both, &[h(1)], |_| vec![h(9)], &[h(5)]),
        OnGetInitStateOutcome::Ban("sent more than one getinitstate".to_string())
    );

    // Below stake validation: blank.
    assert_eq!(
        on_get_init_state(false, svh - 2, svh, both, &[h(1)], |_| vec![h(9)], &[h(5)]),
        OnGetInitStateOutcome::Blank
    );

    // The head blocks are capped at eight and their votes extended in
    // order.
    let eligible: Vec<Hash> = (0..10).map(h).collect();
    let out = on_get_init_state(
        false,
        past,
        svh,
        InitStateWants {
            blocks: true,
            votes: true,
            tspends: false,
        },
        &eligible,
        |b| vec![h(100 + b.0[0])],
        &[],
    );
    match out {
        OnGetInitStateOutcome::Filled {
            block_hashes,
            vote_hashes,
            tspend_hashes,
        } => {
            assert_eq!(block_hashes.len(), MAX_IS_BLOCKS_AT_HEAD);
            assert_eq!(block_hashes, eligible[..MAX_IS_BLOCKS_AT_HEAD]);
            // One vote per capped block, in order.
            let want_votes: Vec<Hash> = (0..MAX_IS_BLOCKS_AT_HEAD as u8)
                .map(|b| h(100 + b))
                .collect();
            assert_eq!(vote_hashes, want_votes);
            assert!(tspend_hashes.is_empty());
        }
        other => panic!("expected filled, got {other:?}"),
    }

    // Requesting only votes still fetches head blocks to compute their
    // votes, then clears the block list.
    let out = on_get_init_state(
        false,
        past,
        svh,
        InitStateWants {
            blocks: false,
            votes: true,
            tspends: false,
        },
        &[h(1), h(2)],
        |b| vec![h(50 + b.0[0])],
        &[],
    );
    assert_eq!(
        out,
        OnGetInitStateOutcome::Filled {
            block_hashes: Vec::new(),
            vote_hashes: vec![h(51), h(52)],
            tspend_hashes: Vec::new(),
        }
    );

    // Treasury spends pass through when requested.
    let out = on_get_init_state(
        false,
        past,
        svh,
        InitStateWants {
            blocks: false,
            votes: false,
            tspends: true,
        },
        &[h(1)],
        |_| Vec::new(),
        &[h(7), h(8)],
    );
    assert_eq!(
        out,
        OnGetInitStateOutcome::Filled {
            block_hashes: Vec::new(),
            vote_hashes: Vec::new(),
            tspend_hashes: vec![h(7), h(8)],
        }
    );

    // Over-limit votes and treasury spends are dropped as build
    // errors.
    let many_votes = on_get_init_state(
        false,
        past,
        svh,
        InitStateWants {
            blocks: true,
            votes: true,
            tspends: false,
        },
        &[h(1)],
        |_| {
            (0..=MAX_IS_VOTES_AT_HEAD as u16)
                .map(|i| h(i as u8))
                .collect()
        },
        &[],
    );
    assert_eq!(many_votes, OnGetInitStateOutcome::BuildError);

    let many_tspends = on_get_init_state(
        false,
        past,
        svh,
        InitStateWants {
            blocks: false,
            votes: false,
            tspends: true,
        },
        &[],
        |_| Vec::new(),
        &(0..=MAX_IS_TSPENDS_AT_HEAD as u8)
            .map(h)
            .collect::<Vec<_>>(),
    );
    assert_eq!(many_tspends, OnGetInitStateOutcome::BuildError);
}
